const entry: BFCacheEntry = {
  rsc,
  prefetchRsc,

  // TODO: These fields will be removed from both BFCacheEntry and
  // SegmentCacheEntry. The head has its own separate cache entry.
  head,
  prefetchHead,

  bfcacheId,

  ref: null,
  // TODO: This is just a heuristic. Getting the actual size of the segment
  // isn't feasible because it's part of a larger streaming response. The
  // LRU will still evict it, we just won't have a fully accurate total
  // LRU size. However, we'll probably remove the size tracking from the LRU
  // entirely and use memory pressure events instead.
  size: 100,

  navigatedAt: now,

  // A back/forward navigation will disregard the stale time. This field is
  // only relevant when staleTimes.dynamic is enabled or unstable_dynamicStaleTime
  // is exported by a page.
  staleAt: dynamicStaleAt,
  version: currentBfCacheVersion,
  status: EntryStatus.Fulfilled,
}

if (renderOpts.cacheComponents) {
  // Only run instant validation once per route, even if multiple param sets from generateStaticParams exist.
  const routesWithInstantValidation = new Set<string>()

  for (const exportPath of allExportPaths) {
    if (exportPath._allowEmptyStaticShell) {
      finalPhaseExportPaths.push(exportPath)
    } else {
      initialPhaseExportPaths.push(exportPath)
    }

    // Always mark routes for potential build validation. The actual
    // decision of whether to validate is made per-route by
    // anySegmentNeedsInstantValidationInBuild, which checks both the
    // default validation level and per-segment level overrides.
    const route = exportPath.page
    if (!routesWithInstantValidation.has(route)) {
      exportPath._runInstantValidation = true
      routesWithInstantValidation.add(route)
    }
  }
} else {
  initialPhaseExportPaths = allExportPaths
}

const handleUnrecognizedFetchAction = (err: unknown): HandleActionResult => {
  // If the deployment doesn't have skew protection, this is expected to occasionally happen,
  // so we use a warning instead of an error.
  console.warn(err)

  // Return an empty response with a header that the client router will interpret.
  // We don't need to waste time encoding a flight response, and using a blank body + header
  // means that unrecognized actions can also be handled at the infra level
  // (i.e. without needing to invoke a lambda)
  res.setHeader(NEXT_ACTION_NOT_FOUND_HEADER, '1')
  res.setHeader('content-type', 'text/plain')
  res.statusCode = 404
  return {
    type: 'done',
    result: RenderResult.fromStatic('Server action not found.', 'text/plain'),
  }
}

