  globalThisWithManifests[MANIFESTS_SINGLETON] = {
    clientReferenceManifestsPerRoute,
    proxiedClientReferenceManifest,
    serverActionsManifest,
    serverModuleMap: createServerModuleMap(),
  }
}

if (!ignoreLoggingIncomingRequests(request, loggingConfig)) {
  logIncomingRequests(
    request,
    requestStartTime,
    requestEndTime,
    response.statusCode,
    devRequestTimingMiddlewareStart,
    devRequestTimingMiddlewareEnd,
    devRequestTimingInternalsEnd,
