for (const fileName of libraryManifestsSupportingNextjsReact) {
  const packageJsonPath = path.join(cwd, fileName)
  const packageJson = await fsp.readFile(packageJsonPath, 'utf-8')
  const manifest = JSON.parse(packageJson)
  // Need to specify last supported RC version to avoid breaking changes.
  if (manifest.peerDependencies['react']) {
    manifest.peerDependencies['react'] = pagesRouterReactVersion
  }
  if (manifest.peerDependencies['react-dom']) {
    manifest.peerDependencies['react-dom'] = pagesRouterReactVersion
  }
  await fsp.writeFile(
    packageJsonPath,
    JSON.stringify(manifest, null, 2) +
      // Prettier would add a newline anyway so do it manually to skip the additional `pnpm prettier-write`
      '\n'
  )
}

export async function resolveImportWithMetadata(importPath: string, config: ResolveImportConfig) {
  const cwd = config.cwd ?? config.absoluteBaseUrl
  if (importPath.startsWith("#")) {
    const resolved = resolvePackageImport(importPath, cwd)
    if (resolved) {
      return { path: resolved.path, source: "package_imports",
        matchedAlias: resolved.matchedAlias, matchedTarget: resolved.matchedTarget,
        emitMode: resolved.emitMode } satisfies ResolvedImport
    }
  }
  const ws = await resolveWorkspacePackageExport(importPath, cwd)
  if (ws) {
    return { path: ws.path, source: "workspace_package_exports",
      matchedAlias: ws.matchedAlias, matchedTarget: ws.matchedTarget,
      emitMode: ws.emitMode } satisfies ResolvedImport
  }
  return resolveFromTsconfigPaths(importPath, config)
}

try {
  const styleMap = await getStyleMap(styleName)
  const transformed = await transformStyle(code, { styleMap })
  const config = buildDisplayConfig(styleName)
  const project = new Project({ compilerOptions: {} })
  const sourceFile = project.createSourceFile("component.tsx", transformed, {
    scriptKind: ScriptKind.TSX,
