if (!clientInformation) {
  if (authorizationCode !== undefined) {
    throw new Error(
      'Existing OAuth client information is required when exchanging an authorization code',
    );
  }

  if (!provider.saveClientInformation) {
    throw new Error(
      'OAuth client information must be saveable for dynamic registration',
    );
  }

  const fullInformation = await registerClient(authorizationServerUrl, {
    metadata,
    clientMetadata: provider.clientMetadata,
    fetchFn,
  });

  clientInformation = addAuthorizationServerInformationToClientInformation(
    fullInformation,
    currentAuthorizationServerInformation,
  );
  await provider.saveClientInformation(clientInformation);
}

for (const el of arrayLiteral.elements) {
  if (!ts.isObjectLiteralExpression(el)) continue;
  const name = getProp(el, 'name');
  if (!name || !ts.isStringLiteralLike(name.initializer)) {
    report({
      pos: el.getStart(),
      message: 'parameter object is missing a string `name`',
    });
  }
  // Recurse into nested groups: properties: [{ type, parameters: [...] }]
  const properties = getProp(el, 'properties');
  if (properties && ts.isArrayLiteralExpression(properties.initializer)) {
    for (const group of properties.initializer.elements) {
      if (!ts.isObjectLiteralExpression(group)) continue;
      const params = getProp(group, 'parameters');
      if (params && ts.isArrayLiteralExpression(params.initializer)) {
        validateParameterList(params.initializer, report);
      }
    }
  }
}

if (hydrationErrorState.warning) {
  // The patched console.error found hydration errors logged by React
  // Append the logged warning to the error message
  parsedHydrationErrorState = {
    // It contains the warning, component stack, server and client tag names
    ...hydrationErrorState,
  }

  // Consume the cached hydration diff.
  // This is only required for now when we still squashed the hydration diff log into hydration error.
  // Once the all error is logged to dev overlay in order, this will go away.
  if (hydrationErrorState.reactOutputComponentDiff) {
    parsedHydrationErrorState.reactOutputComponentDiff =
      hydrationErrorState.reactOutputComponentDiff
  }

  squashedHydrationErrorDetails.set(error, parsedHydrationErrorState)
}

